sql:
SELECT product_id, purchase_price
FROM purchases
WHERE purchase_id = 0;

external_knowledge:
- 'Sellable products' refers to products with 'can_be_sold = 1';
- 'Supplied through either buying or manufacturing' means products with a supply method name of either 'Buy' or 'Manufacture';
- 'Some sales' refers to products with a total quantity sold greater than 0;
- 'Highest sales to lowest' represents the descending order of total quantity sold.
